/**
 * Departments Management Page
 * List, add, delete departments
 */

import React, { useState, useEffect } from 'react';
import { getDepartments, createDepartment, deleteDepartment } from '../../services/admin_service';
import SearchBar from '../../components/common/SearchBar';
import LoadingSpinner from '../../components/common/LoadingSpinner';
import ConfirmModal from '../../components/common/ConfirmModal';

const Departments = () => {
    const [departments, setDepartments] = useState([]);
    const [filteredDepts, setFilteredDepts] = useState([]);
    const [loading, setLoading] = useState(true);
    const [searchTerm, setSearchTerm] = useState('');
    const [showAddModal, setShowAddModal] = useState(false);
    const [showDeleteModal, setShowDeleteModal] = useState(false);
    const [selectedDept, setSelectedDept] = useState(null);
    const [newDeptName, setNewDeptName] = useState('');
    const [error, setError] = useState('');

    useEffect(() => {
        fetchDepartments();
    }, []);

    useEffect(() => {
        filterDepartments();
    }, [searchTerm, departments]);

    const fetchDepartments = async () => {
        setLoading(true);
        const result = await getDepartments();
        if (result.success) {
            setDepartments(result.data || []);
        } else {
            setError(result.message);
        }
        setLoading(false);
    };

    const filterDepartments = () => {
        if (!searchTerm) {
            setFilteredDepts(departments);
        } else {
            const filtered = departments.filter(dept =>
                dept.name?.toLowerCase().includes(searchTerm.toLowerCase())
            );
            setFilteredDepts(filtered);
        }
    };

    const handleAddDepartment = async () => {
        if (!newDeptName.trim()) {
            setError('Department name is required');
            return;
        }

        const result = await createDepartment({ name: newDeptName });
        if (result.success) {
            setShowAddModal(false);
            setNewDeptName('');
            fetchDepartments();
        } else {
            setError(result.message);
        }
    };

    const handleDeleteDepartment = async () => {
        if (!selectedDept) return;

        const result = await deleteDepartment(selectedDept.department_id);
        if (result.success) {
            setShowDeleteModal(false);
            setSelectedDept(null);
            fetchDepartments();
        } else {
            setError(result.message);
        }
    };

    if (loading) return <LoadingSpinner />;

    return (
        <div className="page-container">
            <div className="page-header">
                <h1>Departments</h1>
                <p>{departments.length} departments total</p>
            </div>

            <div className="page-actions">
                <SearchBar
                    placeholder="Search departments..."
                    onSearch={setSearchTerm}
                />
                <button className="btn-primary" onClick={() => setShowAddModal(true)}>
                    + Add Department
                </button>
            </div>

            {error && <div className="error-message">{error}</div>}

            <div className="data-table-container">
                <table className="data-table">
                    <thead>
                        <tr>
                            <th>ID</th>
                            <th>Department Name</th>
                            <th>Actions</th>
                        </tr>
                    </thead>
                    <tbody>
                        {filteredDepts.map((dept) => (
                            <tr key={dept.department_id}>
                                <td>{dept.department_id}</td>
                                <td><strong>{dept.name}</strong></td>
                                <td>
                                    <button
                                        className="btn-icon btn-danger"
                                        onClick={() => {
                                            setSelectedDept(dept);
                                            setShowDeleteModal(true);
                                        }}
                                    >
                                        🗑️
                                    </button>
                                </td>
                            </tr>
                        ))}
                    </tbody>
                </table>
                {filteredDepts.length === 0 && (
                    <div className="empty-state">No departments found</div>
                )}
            </div>

            {/* Add Modal */}
            <ConfirmModal
                isOpen={showAddModal}
                onClose={() => setShowAddModal(false)}
                onConfirm={handleAddDepartment}
                title="Add Department"
                message={
                    <div>
                        <label>Department Name:</label>
                        <input
                            type="text"
                            value={newDeptName}
                            onChange={(e) => setNewDeptName(e.target.value)}
                            placeholder="e.g., Computer Science"
                            className="modal-input"
                        />
                    </div>
                }
                confirmText="Add"
                confirmVariant="primary"
            />

            {/* Delete Modal */}
            <ConfirmModal
                isOpen={showDeleteModal}
                onClose={() => setShowDeleteModal(false)}
                onConfirm={handleDeleteDepartment}
                title="Delete Department"
                message={`Are you sure you want to delete "${selectedDept?.name}"? This will also delete all associated courses and schedules.`}
                confirmText="Delete"
                confirmVariant="danger"
            />
        </div>
    );
};

export default Departments;
